import ldap

def search_user_by_username(ldap_url, username):
    try:
        # Connect to the LDAP server
        ldap_conn = ldap.initialize(ldap_url)
        ldap_conn.simple_bind_s()  # Assuming no authentication is required for searching
        
        # Search for the user by username
        base_dn = "dc=example,dc=com"  # Replace with your actual base DN
        search_filter = f"(uid={username})"
        attributes = ["cn", "mail"]
        
        result_id = ldap_conn.search(base_dn, ldap.SCOPE_SUBTREE, search_filter, attributes)
        results = []
        
        while True:
            result_type, result_data = ldap_conn.result(result_id, 0)
            if result_type == -1:
                break
            elif result_type == ldap.RES_SEARCH_ENTRY:
                entries = [entry for entry in result_data]
                results.extend(entries)
        
        # Close the LDAP connection
        ldap_conn.unbind_s()
        
        return results
    except ldap.LDAPError as e:
        print(f"LDAP Error: {e}")
        return []

